    sort(edges.begin(), edges.end(), [](const auto& a, const auto& b) {
        return a[2] < b[2];
    });
    long long low = 0, high = 0;
    for (auto& e : edges) {
        high = max(high, e[2]);
    }
    long long answer = high;
    while (low <= high) {
        long long mid = (low + high) / 2;
        DSU dsu(n);
        for (auto& e : edges) {
            if (e[2] <= mid) {
                dsu.union(e[0], e[1]);
            }
        }
        if (dsu.get_count() <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}

