        self.parent = list(range(n))
        self.rank = [1] * n
        self.count = n  # number of connected components

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1
        self.count -= 1


def solve(n: int, edges: list[list[int]], k: int) -> int:
    edges.sort(key=lambda x: x[2])
    max_w = max(e[2] for e in edges)
    low = 0
    high = max_w
    answer = max_w
    while low <= high:
        mid = (low + high) // 2
        dsu = DSU(n)
        for u, v, w in edges:
            if w <= mid:
                dsu.union(u, v)
        if dsu.count <= k:
            answer = mid
            high = mid - 1
        else:
            low = mid + 1
    return answer
